def autocomplete(history, queries):
    # Build frequency map (sum frequencies for duplicate words)
    freq = {}
    for word, f in history:
        freq[word] = freq.get(word, 0) + f

    # Build trie
    trie = {}
    for word in freq:
        node = trie
        for ch in word:
            if ch not in node:
                node[ch] = {}
            node = node[ch]
        node['$'] = word  # mark end of word

    def collect_words(node):
        """Collect all words stored under this trie node using DFS."""
        results = []
        stack = [node]
        while stack:
            curr = stack.pop()
            if '$' in curr:
                results.append(curr['$'])
            for key in curr:
                if key != '$':
                    stack.append(curr[key])
        return results

    results = []
    for prefix, k in queries:
        # Navigate trie to the prefix node
        node = trie
        found = True
        for ch in prefix:
            if ch not in node:
                found = False
                break
            node = node[ch]

        if not found:
            results.append([])
        else:
            # Collect all words with this prefix
            words = collect_words(node)
            # Sort by (-frequency, lexicographic order)
            words.sort(key=lambda w: (-freq[w], w))
            results.append(words[:k])

    return results
